def find_heading(doc, title):
    for i, p in enumerate(doc.paragraphs):
        if p.text.strip() == title.strip():
            return i, p
    raise KeyError(f"Heading not found: {title!r}")


def section_end(doc, start_idx):
    for i in range(start_idx + 1, len(doc.paragraphs)):
        sn = doc.paragraphs[i].style.name
        if sn.startswith("Heading"):
            return i
    return len(doc.paragraphs)


def replace_section_body(doc, heading_para, new_paragraphs, captions=None, table_title=None):
    start_idx = None
    for i, p in enumerate(doc.paragraphs):
        if p is heading_para._element:
            start_idx = i
            break
    if start_idx is None:
        for i, p in enumerate(doc.paragraphs):
            if p._element is heading_para._element:
                start_idx = i
                break
    start_idx = [i for i, p in enumerate(doc.paragraphs) if p._element is heading_para._element][0]
    end_idx = section_end(doc, start_idx)

    for i in range(end_idx - 1, start_idx, -1):
        el = doc.paragraphs[i]._element
        el.getparent().remove(el)

    ref = heading_para._element

    for text in new_paragraphs:
        new_el = OxmlElement("w:p")
        ref.addnext(new_el)
        ref = new_el
        para = Paragraph(new_el, heading_para._parent)
        if text.startswith("Рисунок "):
            para.style = doc.styles[CAPTION_STYLE]
        else:
            para.style = doc.styles["Normal"]
        para.text = text


def update_table(table, rows):
    while len(table.rows) > 1:
        table._tbl.remove(table.rows[-1]._tr)
    for row_data in rows:
        row = table.add_row()
        for i, val in enumerate(row_data):
            row.cells[i].text = val


def build_section_paragraphs(_key, texts):
    return list(texts)


def main():
    files = glob.glob("*ВКР*.docx")
    path = [f for f in files if "backup" not in f.lower()][0]
    doc = Document(path)

    # от конца к началу по позиции в документе
    items = []
    for title in SECTIONS:
        idx, para = find_heading(doc, title)
        items.append((idx, title, para))
    items.sort(key=lambda x: x[0], reverse=True)

    for _, title, para in items:
        texts = build_section_paragraphs(title, SECTIONS[title])
        replace_section_body(doc, para, texts)

    update_table(doc.tables[11], TABLE_11_ROWS)
    update_table(doc.tables[12], TABLE_12_ROWS)

    doc.save(path)
    print(f"Saved: {path}\nChar counts:")
    for title in SECTIONS:
        _, para = find_heading(doc, title)
        start = [i for i, p in enumerate(doc.paragraphs) if p._element is para._element][0]
        end = section_end(doc, start)
        total = sum(len(doc.paragraphs[i].text) for i in range(start + 1, end))
        print(f"  {title}: {total} chars")


if __name__ == "__main__":
    main()
